func (this *BitvavoCore) ParseTrade(trade any, optionalArgs ...any) any {
	//
	// fetchTrades (public)
	//
	//     {
	//         "id":"94154c98-6e8b-4e33-92a8-74e33fc05650",
	//         "timestamp":1590382761859,
	//         "amount":"0.06026079",
	//         "price":"8095.3",
	//         "side":"buy"
	//     }
	//
	// createOrder, fetchOpenOrders, fetchOrders, editOrder (private)
	//
	//     {
	//         "id":"b0c86aa5-6ed3-4a2d-ba3a-be9a964220f4",
	//         "timestamp":1590505649245,
	//         "amount":"0.249825",
	//         "price":"183.49",
	//         "taker":true,
	//         "fee":"0.12038925",
	//         "feeCurrency":"EUR",
	//         "settled":true
	//     }
	//
	// fetchMyTrades (private)
	//
	//     {
	//         "id":"b0c86aa5-6ed3-4a2d-ba3a-be9a964220f4",
	//         "orderId":"af76d6ce-9f7c-4006-b715-bb5d430652d0",
	//         "timestamp":1590505649245,
	//         "market":"ETH-EUR",
	//         "side":"sell",
	//         "amount":"0.249825",
	//         "price":"183.49",
	//         "taker":true,
	//         "fee":"0.12038925",
	//         "feeCurrency":"EUR",
	//         "settled":true
	//     }
	//
	// watchMyTrades (private)
	//
	//     {
	//         "event": "fill",
	//         "timestamp": 1590964470132,
	//         "market": "ETH-EUR",
	//         "orderId": "85d082e1-eda4-4209-9580-248281a29a9a",
	//         "fillId": "861d2da5-aa93-475c-8d9a-dce431bd4211",
	//         "side": "sell",
	//         "amount": "0.1",
	//         "price": "211.46",
	//         "taker": true,
	//         "fee": "0.056",
	//         "feeCurrency": "EUR"
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var priceString any = this.SafeString(trade, "price")
	var amountString any = this.SafeString(trade, "amount")
	var timestamp any = this.SafeInteger(trade, "timestamp")
	var side any = this.SafeString(trade, "side")
	var id any = this.SafeString2(trade, "id", "fillId")
	var marketId any = this.SafeString(trade, "market")
	var symbol any = this.SafeSymbol(marketId, market, "-")
	var taker any = this.SafeValue(trade, "taker")
	var takerOrMaker any = nil
	if IsTrue(!IsEqual(taker, nil)) {
		takerOrMaker = Ternary(IsTrue(taker), "taker", "maker")
	}
	var feeCostString any = this.SafeString(trade, "fee")
	var fee any = nil
	if IsTrue(!IsEqual(feeCostString, nil)) {
		var feeCurrencyId any = this.SafeString(trade, "feeCurrency")
		var feeCurrencyCode any = this.SafeCurrencyCode(feeCurrencyId)
		fee = map[string]any{
			"cost":     feeCostString,
			"currency": feeCurrencyCode,
		}
	}
	var orderId any = this.SafeString(trade, "orderId")
	return this.SafeTrade(map[string]any{
		"info":         trade,
		"id":           id,
		"symbol":       symbol,
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"order":        orderId,
		"type":         nil,
		"side":         side,
		"takerOrMaker": takerOrMaker,
		"price":        priceString,
		"amount":       amountString,
		"cost":         nil,
		"fee":          fee,
	}, market)
}

